import Foundation

/// A 1-second silent AAC/.m4a, embedded as base64 so the image-share placeholder
/// audio has **zero dependency on a bundled resource**. The old approach
/// (`Bundle.main.url(forResource:"silent")`) could silently return nil in a
/// release build → the placeholder `.m4a` never uploaded → the shared photos were
/// orphaned (no `.m4a` anchor = invisible in 我的录音, never mined). Embedding the
/// bytes removes that single point of failure.
enum SilentAudio {
    /// 960-byte silent 1s m4a (16 kHz mono AAC). Decodes to the exact bytes of
    /// the former VoiceDropShare/silent.m4a asset.
    static let data: Data = Data(base64Encoded: base64)!

    private static let base64 = ""
}
